# Overriding

public class Animal {
    public void cry() {
        System.out.println("...");
    }
}

public class Cat extends Animal {
    @Override
    public void cry() {       // 부모꺼 재정의!
        System.out.println("야옹");
    }
}


# Super()

public class Animal {
    String name;
    public Animal(String name) {
        this.name = name;
    }
}

public class Cat extends Animal {
    int age;
    public Cat(String name, int age) {
        super(name);   // 부모 생성자 호출! 
								       // 반드시 첫 라인!
        this.age = age;
    }
}
